export type Cell = [x: number, y: number];

const keyOf = ([x, y]: Cell): string => `${x},${y}`;

const livesNextGeneration = (isAlive: boolean, liveNeighbors: number): boolean =>
  isAlive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;

const neighborsOf = ([x, y]: Cell): Cell[] => [
  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
  [x - 1, y    ],             [x + 1, y    ],
  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
];

type Tally = { cell: Cell; liveNeighbors: number };

const tallyNeighborInfluences = (cells: readonly Cell[]): Map<string, Tally> => {
  const tallies = new Map<string, Tally>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = keyOf(neighbor);
      const existing = tallies.get(k);
      if (existing) {
        existing.liveNeighbors += 1;
      } else {
        tallies.set(k, { cell: neighbor, liveNeighbors: 1 });
      }
    }
  }
  return tallies;
};

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const alive = new Set(cells.map(keyOf));
  const next: Cell[] = [];
  for (const [k, { cell, liveNeighbors }] of tallyNeighborInfluences(cells)) {
    if (livesNextGeneration(alive.has(k), liveNeighbors)) {
      next.push(cell);
    }
  }
  return next;
}

