type NeighborTally = { readonly cell: Cell; readonly liveNeighbors: number };

const tallyNeighborInfluences = (cells: readonly Cell[]): Map<string, NeighborTally> => {
  const tallies = new Map<string, NeighborTally>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = keyOf(neighbor);
      const prior = tallies.get(k)?.liveNeighbors ?? 0;
      tallies.set(k, { cell: neighbor, liveNeighbors: prior + 1 });
    }
  }
  return tallies;
};

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const alive = new Set(cells.map(keyOf));
  const next: Cell[] = [];
  for (const [k, { cell, liveNeighbors }] of tallyNeighborInfluences(cells)) {
    if (livesNextGeneration(alive.has(k), liveNeighbors)) {
      next.push(cell);
    }
  }
  return next;
}
